1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	interface QuoteResult {
17	  premium: number;
18	}
19	
20	const COMPONENT_BLOCK_SIZE = 3;
21	const COMPONENT_BLOCK_PRICE = 60;
22	
23	interface Item {
24	  type: string;
25	  enchantment?: number;
26	  cursed?: boolean;
27	}
28	
29	const CURSED_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	
33	const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
34	
35	const itemSurcharge = (item: Item): number => {
36	  const base = basePremiumFor(item.type);
37	  let surcharge = 0;
38	  if (item.cursed) {
39	    surcharge += base * CURSED_SURCHARGE_RATE;
40	  }
41	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
42	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
43	  }
44	  return surcharge;
45	};
46	
47	const quotePremium = (items: Array<Item>): number => {
48	  const typeCounts: Record<string, number> = {};
49	  for (const item of items) {
50	    typeCounts[item.type] = (typeCounts[item.type] ?? 0) + 1;
51	  }
52	  let total = 0;
53	  for (const [type, count] of Object.entries(typeCounts)) {
54	    if (count === COMPONENT_BLOCK_SIZE) {
55	      total += COMPONENT_BLOCK_PRICE;
56	    } else {
57	      total += count * basePremiumFor(type);
58	    }
59	  }
60	  for (const item of items) {
61	    total += itemSurcharge(item);
62	  }
63	  return total + PROCESSING_FEE;
64	};
65	
66	export const processSteps = (customer: Customer, steps: Array<{ op: string; items: Array<Item> }>): Array<QuoteResult> =>
67	  steps.map((step) => ({
68	    premium: quotePremium(step.items),
69	  }));
